var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SOLDIER_NPC_ADMIN_14","text":{"KOREA":"갑자기... 뭐가 나타난 거지?","JPN":"急に……何かが現れた？","ENG":"What just... appeared all of a sudden?","TWN":"突然……有什麼出現了？"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_ADMIN_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"저 커다란 건...?","JPN":"あのデカいのは……？","ENG":"That huge thing...","TWN":"那個巨大的東西是……？"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"못 보던 차원함선이군.","JPN":"次元艦船？","ENG":"It's a dimensional ship?","TWN":"次元艦船？"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"...콜록.","JPN":"……げほっ。","ENG":"*...Cough*","TWN":"……咳咳。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"야, 뭐하는 거야! 갑자기 함선을 꼬라박으면 어떡해? 앙?","JPN":"おい、何してんだよ！　急に艦船をぶち込んでどうする？　あ？","ENG":"Hey, what are you doing?! How can you just ram the ship in like that? Huh?!","TWN":"喂！你在幹嘛！怎麼可以突然把艦船撞過來？啊？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"누가 일부러 박았다고 그래요? 그 사람이 좌표를 열어준다니까, 남은 동력 다 끌어모아서 진입한 거라고요!","JPN":"わざとではありません！　あの人が座標を開放すると言うので、残った動力をかき集めて進入したのです！","ENG":"Who said we rammed it on purpose? She said she'd open the coordinates, so we gathered all remaining power and forced our way in!","TWN":"誰說我是故意的！是那傢伙說要開放座標，我們只是注入所有剩餘動力而已！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L10_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"쳇. 그 허연멀건 녀석, 자기만 믿으라더니 우릴 대체 어디로 끌어들인 거야?","JPN":"ちっ、あの白いやつ。自分を信じろって言っておいて、オレたちをどこに連れ込んだんだ？","ENG":"Tsk. That pale one told us to trust her, but where exactly did she drag us?","TWN":"嘖。那個白白的傢伙，說什麼相信他，結果把我們帶到哪裡來了？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_DELTA_NULL_NULL","text":{"KOREA":"후후, 어디가 됐건 지긋지긋한 차원통로 한복판 보단 나아보이는데요?","JPN":"ふふ、ここがどこでも、次元通路の真ん中よりはマシな気がしますけどね。","ENG":"Haha, wherever this is, it looks better than the middle of that awful dimensional passage, doesn't it?","TWN":"呵呵，不管怎樣，總比待在那煩人的次元通道中央好吧？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JOOSHIYOON_DELTA_NULL_NULL","text":{"KOREA":"바깥을 보세요, 여러분.","JPN":"外を見てください、皆さん。","ENG":"Look outside, everyone.","TWN":"大家往外看。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"...엄청나게 큰 나무?","JPN":"……すごく大きな木？","ENG":"...An enormous tree?","TWN":"……好大的一棵樹？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_DELTA_NULL_NULL","text":{"KOREA":"그것도 눈에 띄긴 하는데, 그보다 좀 더 아래요.","JPN":"それも目に付きますけど、もっと下です。","ENG":"That stands out too, but look a little lower than that.","TWN":"那也很顯眼，但重點是下面。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"JOOSHIYOON_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"JOOSHIYOON_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"오, 사람들이잖아?","JPN":"お、人がいるな。","ENG":"Oh, they're people!","TWN":"喔，是人耶？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"JOOSHIYOON_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"석화 된 시체나, 사람흉내내는 도플갱어가 아니야...! 진짜 사람이라고!","JPN":"石化した死体とか人間の真似をするドッペルゲンガーじゃない……！　本物の人間だぜ！","ENG":"They're not petrified corpses or Doppelgangers pretending to be people...! They're real people!","TWN":"不是石化的屍體，也不是模仿人類的分身……！是真的人！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"JOOSHIYOON_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"...시영 씨.","JPN":"……シノンさん。","ENG":"...Shiyoung.","TWN":"……時雨。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"JOOSHIYOON_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"저 사람들 옷에 새겨진 마크... 제가 잘못 본 건 아니겠죠?","JPN":"あの人たちの服についているマーク……見間違いではありませんよね？","ENG":"The mark on their clothes... I'm not mistaken, right?","TWN":"那些人衣服上的標誌……我沒看錯吧？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"JOOSHIYOON_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"JOOSHIYOON_DELTA_NULL_NULL","text":{"KOREA":"아무래도 저희가 기억하던 그 마크가 맞는 거 같은데요?","JPN":"どうやら私たちが覚えているあのマークで合っているようですね。","ENG":"It looks like the same mark we remember.","TWN":"看起來，應該就是我們記憶中的那個標誌。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"JOOSHIYOON_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"JOOSHIYOON_DELTA_NULL_NULL","text":{"KOREA":"관.리.국. 맞죠?","JPN":"管理局です。","ENG":"It's the Administration.","TWN":"是管理局。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"JOOSHIYOON_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"JOOSHIYOON_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"드디어...","JPN":"やっと……","ENG":"Finally...","TWN":"終於……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"JOOSHIYOON_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"우리가 찾았, 꺄악!","JPN":"見つけ、きゃあっ！","ENG":"We finally found– AAAH!","TWN":"我們找到了，嗚哇！"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"KEEPER_ANAP_NULL_NULL","text":{"KOREA":"...기발함 하나는 인정하죠.","JPN":"……奇抜さだけは認めましょう。","ENG":"...I'll admit one thing. That was clever.","TWN":"……我承認的確很特別。"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"KEEPER_ANAP_NULL_NULL","text":{"KOREA":"이런 기습은 생각도 못했습니다.","JPN":"こんな不意打ちは思いもよりませんでした。","ENG":"I never expected an ambush like that.","TWN":"我確實沒想到這種戰術。"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"저 역시 이것 하나는 인정해야겠군요.","JPN":"私も一つだけは認めてあげます。","ENG":"There's one thing I must admit as well.","TWN":"我也得承認這一點。"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"차원함선과 박치기를 하고도 멀쩡히 기어 나올 정도로 튼튼할 줄은 몰랐습니다.","JPN":"次元艦船に体当たりされて平気で立ち上がるほど頑丈にできているとは知りませんでした。","ENG":"I didn't expect you to crawl out just fine after colliding head-on with a dimensional ship.","TWN":"沒想到竟然能在和次元艦船對撞後還能毫髮無傷地爬出來，還真夠結實。"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"하지만, 그게 전부는 아닐 겁니다.","JPN":"ですが、これで終わりではありません。","ENG":"But that won't be enough.","TWN":"但應該不只如此吧。"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"KEEPER_ANAP_NULL_NULL","text":{"KOREA":"...뭘 날린 겁니까? 고철뭉치?","JPN":"……何を飛ばしたんですか？　鉄くず？","ENG":"...What did you throw at me? Scrap heap?","TWN":"……你丟了什麼？一堆廢鐵？"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"나이스 캐치-","JPN":"ナイスキャッチ。","ENG":"Nice catch.","TWN":"接得好—"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L39_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"좀 있으면 짜릿해질 거다.","JPN":"もうすぐビリビリするぞ。","ENG":"It'll start getting exciting in a moment.","TWN":"等一下就更刺激了。"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L40_1","type":"dialog","speaker":"KEEPER_ANAP_NULL_NULL","text":{"KOREA":"...?!","JPN":"……！？","ENG":"...?!","TWN":"……！？"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":{"char_id":"KEEPER_ANAP_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}}]`);export{e as default};